Here is the debounce implementation:

```typescript
export interface DebouncedFunction<T extends (...args: unknown[]) => void> {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(): void;
  pending(): boolean;
}

export function debounce<T extends (...args: unknown[]) => void>(fn: T, waitMs: number): DebouncedFunction<T> {
  let timer: ReturnType<typeof setTimeout> | undefined;
  let lastArgs: Parameters<T> | undefined;

  function debounced(...args: Parameters<T>): void {
    lastArgs = args;
    if (timer !== undefined) clearTimeout(timer);
    timer = setTimeout(() => {
      timer = undefined;
      const a = lastArgs!; lastArgs = undefined;
      fn(...a);
    }, waitMs);
  }

  debounced.cancel = (): void => {
    if (timer !== undefined) { clearTimeout(timer); timer = undefined; }
    lastArgs = undefined;
  };

  debounced.flush = (): void => {
    if (timer !== undefined) {
      clearTimeout(timer); timer = undefined;
      const a = lastArgs!; lastArgs = undefined;
      fn(...a);
    }
  };

  debounced.pending = (): boolean => timer !== undefined;

  return debounced as DebouncedFunction<T>;
}
